def fmt_gct(sample_ids, table):
    if not isinstance(sample_ids, (list, tuple)) or not all(isinstance(id, str) for id in sample_ids):
        raise ValueError("sample_ids must be a list or tuple of strings.")

    if not hasattr(table, '__len__') or len(table) == 0 or not all(len(row) > 0 for row in table):
        raise ValueError("table must be a non-empty structured format with rows of data.")

    num_genes = len(table)
    num_samples = len(sample_ids)

    header = f"#1.2\n{num_genes}\t{num_samples}\n"

    data_lines = []
    for row in table:
        gene_id = row[0]
        gene_name = row[1] if len(row) > 1 else ""
        expression_values = "\t".join(map(str, row[2:num_samples + 2]))
        data_lines.append(f"{gene_id}\t{gene_name}\t{expression_values}")

    return header + "\n".join(data_lines)

