            elif rec1[2].startswith('<INS:') and rec2[2].startswith('<INS:') and rec1[2] != rec2[2]:
                counts['ins_alt_different_subtype'] += 1
                f_records.write(f"ins_alt_different_subtype\t{rec1[0]},{rec2[0]}\n")

