def phaseplot_validate(fp, fn):
    try:
        fp = float(fp)
    except ValueError as e:
        raise PlottingException(
            "Unable to convert " +
            str(fp) +
            " into a float")

    try:
        fn = float(fn)
    except ValueError as e:
        raise PlottingException(
            "Unable to convert " +
            str(fn) +
            " into a float")

    if (fp < 0) or (fp > 1):
        raise PlottingException(
            "Fraction of positive residues outside of appropriate range [" + str(fp) + "]")
    if (fn < 0) or (fn > 1):
