def _one_autocorr(seq, window, scale):
    try:
        m = list()
        for shp in range(len(seq)):
            m.append(scale[str(seq[shp])])
        seqdesc = list()
        for dist in range(window):
            for val in range(len(scale["A"])):
                valsum = list()
                cntr = 0.0
                for pos in range(len(seq)):
                    if (pos + dist) < len(seq):
                        cntr += 1
                        valsum.append(m[pos][val] * m[pos + dist][val])
                seqdesc.append(sum(valsum) / cntr)
        return seqdesc
    except ZeroDivisionError:
        return "ERROR!\nThe chosen correlation window % i is larger than the sequence %s !" % (window, seq)

